	svc.PUT("/:id", serviceHandler.UpdateService, middleware.RoleGuard("Administrator", "Scheduler"))
	svc.DELETE("/:id", serviceHandler.DeleteService, middleware.RoleGuard("Administrator"))

	// Schedules
