6	-- ----------------------------------------------------------------------------
7	-- 1. Users: Add rolling-window login tracking, CAPTCHA answer, location support
8	-- ----------------------------------------------------------------------------
9	ALTER TABLE users ADD COLUMN IF NOT EXISTS last_failed_at TIMESTAMPTZ;
10	ALTER TABLE users ADD COLUMN IF NOT EXISTS captcha_answer INT;
