16	    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
17	    tenant_id UUID NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
18	    name VARCHAR(255) NOT NULL,
19	    address TEXT,
20	    is_active BOOLEAN NOT NULL DEFAULT TRUE,
21	    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
22	    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
23	);
24	
25	CREATE INDEX IF NOT EXISTS idx_locations_tenant ON locations(tenant_id);
26	CREATE INDEX IF NOT EXISTS idx_locations_active ON locations(is_active);
27	
28	ALTER TABLE users ADD COLUMN IF NOT EXISTS location_id UUID REFERENCES locations(id);
