68	-- ----------------------------------------------------------------------------
69	-- 7. Audit ledger immutability: DB-level triggers to prevent UPDATE/DELETE
70	-- ----------------------------------------------------------------------------
71	CREATE OR REPLACE FUNCTION prevent_audit_ledger_modification()
72	RETURNS TRIGGER AS $$
73	BEGIN
74	    RAISE EXCEPTION 'audit_ledger is append-only: % operations are not allowed', TG_OP;
75	    RETURN NULL;
76	END;
77	$$ LANGUAGE plpgsql;
78	
79	-- Drop triggers first to make migration idempotent
80	DROP TRIGGER IF EXISTS audit_ledger_no_update ON audit_ledger;
81	DROP TRIGGER IF EXISTS audit_ledger_no_delete ON audit_ledger;
82	
83	CREATE TRIGGER audit_ledger_no_update
84	    BEFORE UPDATE ON audit_ledger
85	    FOR EACH ROW EXECUTE FUNCTION prevent_audit_ledger_modification();
86	
87	CREATE TRIGGER audit_ledger_no_delete
88	    BEFORE DELETE ON audit_ledger
89	    FOR EACH ROW EXECUTE FUNCTION prevent_audit_ledger_modification();
90	
91	-- Functions to temporarily disable/enable triggers for authorized retention cleanup
92	CREATE OR REPLACE FUNCTION disable_audit_ledger_triggers() RETURNS void AS $$
93	BEGIN
94	    ALTER TABLE audit_ledger DISABLE TRIGGER audit_ledger_no_update;
95	    ALTER TABLE audit_ledger DISABLE TRIGGER audit_ledger_no_delete;
96	END;
97	$$ LANGUAGE plpgsql;
98	
99	CREATE OR REPLACE FUNCTION enable_audit_ledger_triggers() RETURNS void AS $$
100	BEGIN
101	    ALTER TABLE audit_ledger ENABLE TRIGGER audit_ledger_no_update;
102	    ALTER TABLE audit_ledger ENABLE TRIGGER audit_ledger_no_delete;
103	END;
104	$$ LANGUAGE plpgsql;
105	
106	-- ----------------------------------------------------------------------------
107	-- 7a. Schedules: Add pending_staff_id for reassignment confirmation workflow
108	-- ----------------------------------------------------------------------------
109	ALTER TABLE schedules ADD COLUMN IF NOT EXISTS pending_staff_id UUID REFERENCES staff_roster(id);
110	
111	-- ----------------------------------------------------------------------------
112	-- 7b. Protect critical audit_logs entries from mutation
113	-- ----------------------------------------------------------------------------
114	CREATE OR REPLACE FUNCTION prevent_critical_audit_log_modification()
115	RETURNS trigger AS $$
116	DECLARE
117	    critical_actions TEXT[] := ARRAY[
118	        'login', 'logout', 'login_failed',
119	        'create_user', 'deactivate_user', 'update_user_role',
120	        'review_decision', 'promote_content', 'rollback_content',
121	        'create_schedule', 'cancel_schedule', 'confirm_assignment', 'reassign_schedule',
122	        'store_sensitive_data', 'reveal_sensitive_data', 'rotate_encryption_key',
123	        'resolve_exception', 'assign_exception'
124	    ];
125	BEGIN
126	    IF OLD.action = ANY(critical_actions) THEN
127	        RAISE EXCEPTION 'Cannot modify or delete critical audit log entries (action: %)', OLD.action;
128	        RETURN NULL;
129	    END IF;
130	    IF TG_OP = 'DELETE' THEN
131	        RETURN OLD;
132	    END IF;
133	    RETURN NEW;
134	END;
135	$$ LANGUAGE plpgsql;
136	
137	DROP TRIGGER IF EXISTS audit_logs_protect_critical_update ON audit_logs;
138	DROP TRIGGER IF EXISTS audit_logs_protect_critical_delete ON audit_logs;
139	
140	CREATE TRIGGER audit_logs_protect_critical_update
141	    BEFORE UPDATE ON audit_logs
142	    FOR EACH ROW EXECUTE FUNCTION prevent_critical_audit_log_modification();
143	
144	CREATE TRIGGER audit_logs_protect_critical_delete
145	    BEFORE DELETE ON audit_logs
146	    FOR EACH ROW EXECUTE FUNCTION prevent_critical_audit_log_modification();
147	
148	-- ----------------------------------------------------------------------------
149	-- 8. Seed default retention policies
150	-- ----------------------------------------------------------------------------
151	INSERT INTO retention_policies (id, table_name, retention_years, is_active)
152	VALUES
153	    (uuid_generate_v4(), 'audit_ledger', 7, TRUE),
154	    (uuid_generate_v4(), 'audit_logs', 7, TRUE)
155	ON CONFLICT DO NOTHING;
