27	// ListStaff returns all staff members for the current tenant.
28	func (h *StaffHandler) ListStaff(c echo.Context) error {
29		tenantID := middleware.GetTenantIDFromContext(c)
30	
31		rows, err := h.DB.Query(`
32			SELECT id, tenant_id, user_id, full_name, specialization,
33			       is_available, created_at, updated_at
34			FROM staff_roster
35			WHERE tenant_id = $1
36			ORDER BY full_name ASC
37		`, tenantID)
38		if err != nil {
39			return c.JSON(http.StatusInternalServerError, map[string]string{
40				"error": "Failed to fetch staff",
41			})
42		}
43		defer rows.Close()
44	
45		var staff []models.StaffMember
46		for rows.Next() {
47			var s models.StaffMember
48			err := rows.Scan(
49				&s.ID, &s.TenantID, &s.UserID, &s.FullName, &s.Specialization,
50				&s.IsAvailable, &s.CreatedAt, &s.UpdatedAt,
51			)
52			if err != nil {
53				return c.JSON(http.StatusInternalServerError, map[string]string{
54					"error": "Failed to scan staff member",
55				})
56			}
57			staff = append(staff, s)
58		}
59	
60		if staff == nil {
61			staff = []models.StaffMember{}
62		}
63	
64		return c.JSON(http.StatusOK, staff)
65	}
