101	// CreateStaff creates a new staff member.
102	func (h *StaffHandler) CreateStaff(c echo.Context) error {
103		currentUser := middleware.GetUserFromContext(c)
104		tenantID := middleware.GetTenantIDFromContext(c)
105	
106		var req models.CreateStaffRequest
107		if err := c.Bind(&req); err != nil {
108			return c.JSON(http.StatusBadRequest, map[string]string{
109				"error": "Invalid request body",
110			})
111		}
112	
113		if req.FullName == "" {
114			return c.JSON(http.StatusBadRequest, map[string]string{
115				"error": "Full name is required",
116			})
117		}
118	
119		if req.UserID == uuid.Nil {
120			return c.JSON(http.StatusBadRequest, map[string]string{
121				"error": "User ID is required",
122			})
123		}
124	
125		// Verify the user exists in the same tenant
126		var userExists bool
127		err := h.DB.QueryRow(
128			"SELECT EXISTS(SELECT 1 FROM users WHERE id = $1 AND tenant_id = $2)",
129			req.UserID, tenantID,
130		).Scan(&userExists)
131		if err != nil || !userExists {
132			return c.JSON(http.StatusBadRequest, map[string]string{
133				"error": "User not found in tenant",
134			})
135		}
136	
137		newID := uuid.New()
138		now := time.Now()
139	
140		_, err = h.DB.Exec(`
141			INSERT INTO staff_roster (id, tenant_id, user_id, full_name, specialization, created_at, updated_at)
142			VALUES ($1, $2, $3, $4, $5, $6, $7)
143		`, newID, tenantID, req.UserID, req.FullName, req.Specialization, now, now)
144		if err != nil {
145			return c.JSON(http.StatusInternalServerError, map[string]string{
146				"error": "Failed to create staff member",
147			})
148		}
149	
150		detailsJSON, _ := json.Marshal(req)
151		details := string(detailsJSON)
152		writeAuditLog(h.DB, &tenantID, &currentUser.ID, "create_staff", "staff", &newID, &details, c.RealIP())
153	
154		return h.getStaffByID(c, newID, tenantID, http.StatusCreated)
155	}
