157	// UpdateStaff modifies an existing staff member.
158	func (h *StaffHandler) UpdateStaff(c echo.Context) error {
159		currentUser := middleware.GetUserFromContext(c)
160		tenantID := middleware.GetTenantIDFromContext(c)
161	
162		staffID, err := uuid.Parse(c.Param("id"))
163		if err != nil {
164			return c.JSON(http.StatusBadRequest, map[string]string{
165				"error": "Invalid staff ID",
166			})
167		}
168	
169		var req models.UpdateStaffRequest
170		if err := c.Bind(&req); err != nil {
171			return c.JSON(http.StatusBadRequest, map[string]string{
172				"error": "Invalid request body",
173			})
174		}
175	
176		query := "UPDATE staff_roster SET updated_at = NOW()"
177		args := []interface{}{}
178		argIdx := 1
179	
180		if req.FullName != nil {
181			query += fmt.Sprintf(", full_name = $%d", argIdx)
182			args = append(args, *req.FullName)
183			argIdx++
184		}
185		if req.Specialization != nil {
186			query += fmt.Sprintf(", specialization = $%d", argIdx)
187			args = append(args, *req.Specialization)
188			argIdx++
189		}
190		if req.IsAvailable != nil {
191			query += fmt.Sprintf(", is_available = $%d", argIdx)
192			args = append(args, *req.IsAvailable)
193			argIdx++
194		}
195	
196		query += fmt.Sprintf(" WHERE id = $%d AND tenant_id = $%d", argIdx, argIdx+1)
197		args = append(args, staffID, tenantID)
198	
199		result, err := h.DB.Exec(query, args...)
200		if err != nil {
201			return c.JSON(http.StatusInternalServerError, map[string]string{
202				"error": "Failed to update staff member",
203			})
204		}
205	
206		rowsAffected, _ := result.RowsAffected()
207		if rowsAffected == 0 {
208			return c.JSON(http.StatusNotFound, map[string]string{
209				"error": "Staff member not found",
210			})
211		}
212	
213		detailsJSON, _ := json.Marshal(req)
214		details := string(detailsJSON)
215		writeAuditLog(h.DB, &tenantID, &currentUser.ID, "update_staff", "staff", &staffID, &details, c.RealIP())
216	
217		return h.getStaffByID(c, staffID, tenantID, http.StatusOK)
218	}
