181	// UpdateUser modifies an existing user.
182	func (h *UserHandler) UpdateUser(c echo.Context) error {
183		currentUser := middleware.GetUserFromContext(c)
184		tenantID := middleware.GetTenantIDFromContext(c)
185	
186		userID, err := uuid.Parse(c.Param("id"))
187		if err != nil {
188			return c.JSON(http.StatusBadRequest, map[string]string{
189				"error": "Invalid user ID",
190			})
191		}
192	
193		var req models.UpdateUserRequest
194		if err := c.Bind(&req); err != nil {
195			return c.JSON(http.StatusBadRequest, map[string]string{
196				"error": "Invalid request body",
197			})
198		}
199	
200		query := "UPDATE users SET updated_at = NOW()"
201		args := []interface{}{}
202		argIdx := 1
203	
204		if req.RoleID != nil {
205			query += fmt.Sprintf(", role_id = $%d", argIdx)
206			args = append(args, *req.RoleID)
207			argIdx++
208		}
209		if req.Username != nil {
210			query += fmt.Sprintf(", username = $%d", argIdx)
211			args = append(args, *req.Username)
212			argIdx++
213		}
214		if req.Email != nil {
215			query += fmt.Sprintf(", email = $%d", argIdx)
216			args = append(args, *req.Email)
217			argIdx++
218		}
219		if req.IsActive != nil {
220			query += fmt.Sprintf(", is_active = $%d", argIdx)
221			args = append(args, *req.IsActive)
222			argIdx++
223		}
224	
225		query += fmt.Sprintf(" WHERE id = $%d AND tenant_id = $%d", argIdx, argIdx+1)
226		args = append(args, userID, tenantID)
227	
228		result, err := h.DB.Exec(query, args...)
229		if err != nil {
230			return c.JSON(http.StatusInternalServerError, map[string]string{
231				"error": "Failed to update user",
232			})
233		}
234	
235		rowsAffected, _ := result.RowsAffected()
236		if rowsAffected == 0 {
237			return c.JSON(http.StatusNotFound, map[string]string{
238				"error": "User not found",
239			})
240		}
241	
242		detailsJSON, _ := json.Marshal(req)
243		details := string(detailsJSON)
244	
245		// Role changes are critical permission mutations — route through immutable ledger (fail-closed)
246		if req.RoleID != nil {
247			if err := writeCriticalAuditLog(h.AL, h.DB, &tenantID, &currentUser.ID, "update_user_role", "user", &userID, &details, c.RealIP()); err != nil {
248				return c.JSON(http.StatusInternalServerError, map[string]string{
249					"error": "Audit system unavailable, action denied",
250				})
251			}
252		} else {
253			writeAuditLog(h.DB, &tenantID, &currentUser.ID, "update_user", "user", &userID, &details, c.RealIP())
254		}
255	
256		return h.GetUser(c)
257	}
