260	func (h *UserHandler) DeactivateUser(c echo.Context) error {
261		currentUser := middleware.GetUserFromContext(c)
262		tenantID := middleware.GetTenantIDFromContext(c)
263	
264		userID, err := uuid.Parse(c.Param("id"))
265		if err != nil {
266			return c.JSON(http.StatusBadRequest, map[string]string{
