125		}
126	
127		if req.Username == "" || req.Email == "" {
128			return c.JSON(http.StatusBadRequest, map[string]string{
129				"error": "Username and email are required",
130			})
131		}
132	
133		passwordHash, err := HashPasswordArgon2(req.Password)
134		if err != nil {
135			return c.JSON(http.StatusInternalServerError, map[string]string{
136				"error": "Failed to hash password",
137			})
138		}
139	
140		newID := uuid.New()
141		now := time.Now()
142	
143		_, err = h.DB.Exec(`
144			INSERT INTO users (id, tenant_id, role_id, username, email, full_name, password_hash, created_at, updated_at)
145			VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
146		`, newID, tenantID, req.RoleID, req.Username, req.Email, req.FullName, passwordHash, now, now)
147		if err != nil {
148			return c.JSON(http.StatusConflict, map[string]string{
149				"error": "Username or email already exists",
150			})
151		}
152	
153		detailsJSON, _ := json.Marshal(map[string]string{
154			"username": req.Username,
155			"email":    req.Email,
156		})
157		details := string(detailsJSON)
158		if err := writeCriticalAuditLog(h.AL, h.DB, &tenantID, &currentUser.ID, "create_user", "user", &newID, &details, c.RealIP()); err != nil {
159			return c.JSON(http.StatusInternalServerError, map[string]string{
160				"error": "Audit system unavailable, action denied",
161			})
162		}
163	
164		var u models.User
165		_ = h.DB.QueryRow(`
166			SELECT u.id, u.tenant_id, u.role_id, r.name, u.username, u.email, u.full_name,
167			       u.failed_login_attempts, u.locked_until, u.captcha_required,
168			       u.last_login_at, u.created_at, u.updated_at, u.is_active
169			FROM users u
170			JOIN roles r ON u.role_id = r.id
171			WHERE u.id = $1
172		`, newID).Scan(
173			&u.ID, &u.TenantID, &u.RoleID, &u.RoleName, &u.Username, &u.Email, &u.FullName,
174			&u.FailedLoginAttempts, &u.LockedUntil, &u.CaptchaRequired,
175			&u.LastLoginAt, &u.CreatedAt, &u.UpdatedAt, &u.IsActive,
176		)
177	
178		return c.JSON(http.StatusCreated, u)
179	}
