1	// Package unit_tests contains standalone specification tests that validate
2	// reconciliation matching invariants. Production scoring logic is tested
3	// directly in compliance-console/internal/services/reconciliation_test.go.
4	//
5	// These tests document expected matching behavior at a high level.
6	package unit_tests
7	
8	import (
9		"math"
10		"testing"
11		"time"
12	)
13	
14	// NOTE: These tests validate matching INVARIANTS using a simplified scoring model.
15	// The production scoring function is tested directly in:
16	//   backend/internal/services/reconciliation_test.go
17	// Any changes to scoring logic should update BOTH test suites.
18	
19	// Simplified scoring model matching production semantics for specification testing
20	func specScoreAmount(variance float64) float64 {
21		if variance == 0 {
22			return 40
23		} else if variance <= 1.0 {
24			return 20
25		}
26		return 0
27	}
28	
29	func specScoreTime(diffMinutes float64) float64 {
30		if diffMinutes <= 10 {
31			return 30
32		} else if diffMinutes <= 60 {
33			return 10
34		}
35		return 0
36	}
37	
38	// txTimeSpec creates a time for testing
39	func txTimeSpec(hour, minute int) time.Time {
40		return time.Date(2026, 4, 10, hour, minute, 0, 0, time.UTC)
41	}
42	
43	func TestSpec_ExactAmountMatch_HighScore(t *testing.T) {
44		score := specScoreAmount(0)
45		if score != 40 {
46			t.Errorf("exact amount match should yield 40 points, got %.0f", score)
47		}
48	}
49	
50	func TestSpec_SmallAmountVariance_PartialScore(t *testing.T) {
51		score := specScoreAmount(0.50)
52		if score != 20 {
53			t.Errorf("$0.50 variance should yield 20 points, got %.0f", score)
54		}
55	}
56	
57	func TestSpec_LargeAmountVariance_ZeroScore(t *testing.T) {
58		score := specScoreAmount(5.00)
59		if score != 0 {
60			t.Errorf("$5.00 variance should yield 0 points, got %.0f", score)
61		}
62	}
63	
64	func TestSpec_TimestampWithinWindow(t *testing.T) {
65		score := specScoreTime(9)
66		if score != 30 {
67			t.Errorf("9-min difference should yield 30 points, got %.0f", score)
68		}
69	}
70	
71	func TestSpec_TimestampWithinHour(t *testing.T) {
72		score := specScoreTime(30)
73		if score != 10 {
74			t.Errorf("30-min difference should yield 10 points, got %.0f", score)
75		}
76	}
77	
78	func TestSpec_TimestampBeyondHour(t *testing.T) {
79		score := specScoreTime(120)
80		if score != 0 {
81			t.Errorf("120-min difference should yield 0 points, got %.0f", score)
82		}
83	}
84	
85	func TestSpec_VarianceThresholdBoundary(t *testing.T) {
86		tests := []struct {
87			name        string
88			variance    float64
89			expectScore float64
90		}{
91			{"zero", 0, 40},
92			{"$0.01", 0.01, 20},
93			{"$0.99", 0.99, 20},
94			{"$1.00 exactly", 1.00, 20},
95			{"$1.01", 1.01, 0},
96			{"$5.00", 5.00, 0},
97		}
98	
99		for _, tc := range tests {
100			t.Run(tc.name, func(t *testing.T) {
101				score := specScoreAmount(tc.variance)
102				if math.Abs(score-tc.expectScore) > 0.01 {
103					t.Errorf("variance $%.2f: expected %.0f points, got %.0f", tc.variance, tc.expectScore, score)
104				}
105			})
106		}
107	}
108	
109	func TestSpec_DuplicateDetection_Invariants(t *testing.T) {
110		// Same amount + counterparty within 24 hours = duplicate suspect
111		t.Run("same_within_24h", func(t *testing.T) {
112			a := txTimeSpec(10, 0)
113			b := txTimeSpec(10, 5)
114			diff := math.Abs(a.Sub(b).Hours())
115			if diff > 24 {
116				t.Error("5 min apart should be within 24h window")
117			}
118		})
119	
120		t.Run("beyond_24h", func(t *testing.T) {
121			a := txTimeSpec(10, 0)
122			b := a.Add(25 * time.Hour)
123			diff := math.Abs(a.Sub(b).Hours())
124			if diff <= 24 {
125				t.Error("25h apart should be outside 24h window")
126			}
127		})
128	}
