1	// Package unit_tests contains standalone specification tests that validate
2	// scheduling buffer invariants. Production conflict detection is DB-backed
3	// and tested via integration tests in tests/API_tests/.
4	//
5	// The production buffer constant is validated in:
6	//   backend/internal/services/scheduler_test.go
7	package unit_tests
8	
9	import (
10		"testing"
11		"time"
12	)
13	
14	// bufferMinutes mirrors the production BufferDuration (30 min).
15	// If this changes, update to match services.BufferDuration.
16	const bufferMinutes = 30
17	
18	// makeTime builds a time on a fixed date for deterministic testing.
19	func makeTime(hour, minute int) time.Time {
20		return time.Date(2026, 4, 10, hour, minute, 0, 0, time.UTC)
21	}
22	
23	// hasBufferViolation checks the scheduling invariant:
24	// a new schedule [newStart, newEnd] must have at least bufferMinutes gap
25	// from [existingStart, existingEnd].
26	// This mirrors the production exclusion constraint + query logic.
27	func hasBufferViolation(existingStart, existingEnd, newStart, newEnd time.Time) bool {
28		buffer := time.Duration(bufferMinutes) * time.Minute
29	
30		// Direct overlap
31		if newStart.Before(existingEnd) && newEnd.After(existingStart) {
32			return true
33		}
34		// Buffer violation after existing
35		if !newStart.Before(existingEnd) && newStart.Before(existingEnd.Add(buffer)) {
36			return true
37		}
38		// Buffer violation before existing
39		if !newEnd.After(existingStart) && newEnd.After(existingStart.Add(-buffer)) {
40			return true
41		}
42		return false
43	}
44	
45	func TestNoConflict_WellSeparated(t *testing.T) {
46		if hasBufferViolation(makeTime(9, 0), makeTime(10, 0), makeTime(12, 0), makeTime(13, 0)) {
47			t.Error("expected no conflict for well-separated schedules")
48		}
49	}
50	
51	func TestDirectOverlap(t *testing.T) {
52		if !hasBufferViolation(makeTime(9, 0), makeTime(10, 0), makeTime(9, 30), makeTime(10, 30)) {
53			t.Error("expected direct overlap conflict")
54		}
55	}
56	
57	func TestBufferViolation_TooClose(t *testing.T) {
58		if !hasBufferViolation(makeTime(9, 0), makeTime(10, 0), makeTime(10, 15), makeTime(11, 15)) {
59			t.Error("expected buffer violation for schedule starting 15 min after existing ends")
60		}
61	}
62	
63	func TestBufferExact_30Minutes(t *testing.T) {
64		if hasBufferViolation(makeTime(9, 0), makeTime(10, 0), makeTime(10, 30), makeTime(11, 30)) {
65			t.Error("expected no conflict when schedule starts exactly 30 min after existing ends")
66		}
67	}
68	
69	func TestBackToBack_NoBuffer(t *testing.T) {
70		if !hasBufferViolation(makeTime(9, 0), makeTime(10, 0), makeTime(10, 0), makeTime(11, 0)) {
71			t.Error("expected conflict for back-to-back schedule with no buffer")
72		}
73	}
74	
75	func TestBufferBoundaries_TableDriven(t *testing.T) {
76		existingStart := makeTime(10, 0)
77		existingEnd := makeTime(11, 0)
78	
79		tests := []struct {
80			name           string
81			newStartH      int
82			newStartM      int
83			newEndH        int
84			newEndM        int
85			expectConflict bool
86		}{
87			{"well before (OK)", 8, 0, 9, 29, false},
88			{"ends at buffer boundary before (conflict)", 8, 30, 9, 31, true},
89			{"starts 29 min after end (conflict)", 11, 29, 12, 29, true},
90			{"starts exactly 30 min after end (OK)", 11, 30, 12, 30, false},
91			{"starts 31 min after end (OK)", 11, 31, 12, 31, false},
92			{"complete overlap (conflict)", 10, 0, 11, 0, true},
93			{"new contains existing (conflict)", 9, 0, 12, 0, true},
94			{"new within existing (conflict)", 10, 15, 10, 45, true},
95		}
96	
97		for _, tc := range tests {
98			t.Run(tc.name, func(t *testing.T) {
99				newStart := makeTime(tc.newStartH, tc.newStartM)
100				newEnd := makeTime(tc.newEndH, tc.newEndM)
101				conflict := hasBufferViolation(existingStart, existingEnd, newStart, newEnd)
102				if conflict != tc.expectConflict {
103					t.Errorf("expected conflict=%v, got conflict=%v", tc.expectConflict, conflict)
104				}
105			})
106		}
107	}
108	
109	func TestMultipleExistingSchedules(t *testing.T) {
110		type sched struct{ start, end time.Time }
111		existing := []sched{
112			{makeTime(8, 0), makeTime(9, 0)},
113			{makeTime(11, 0), makeTime(12, 0)},
114		}
115	
116		checkAll := func(newStart, newEnd time.Time) bool {
117			for _, s := range existing {
118				if hasBufferViolation(s.start, s.end, newStart, newEnd) {
119					return true
120				}
121			}
122			return false
123		}
124	
125		// Fits between with proper buffer (9:30 - 10:30)
126		if checkAll(makeTime(9, 30), makeTime(10, 30)) {
127			t.Error("expected no conflict for slot fitting between two schedules with buffer")
128		}
129	
130		// Violates buffer of second schedule (10:35 - 10:50, too close to 11:00)
131		if !checkAll(makeTime(10, 35), makeTime(10, 50)) {
132			t.Error("expected conflict for slot ending within buffer before second schedule")
133		}
134	}
