29	// ListServices returns all active services for the current tenant.
30	func (h *ServiceHandler) ListServices(c echo.Context) error {
31		tenantID := middleware.GetTenantIDFromContext(c)
32	
33		rows, err := h.DB.Query(`
34			SELECT id, tenant_id, name, description, base_price_usd, tier,
35			       after_hours_surcharge_pct, same_day_surcharge_usd,
36			       duration_minutes, is_active, headcount, required_tools, add_ons, daily_cap,
37			       created_at, updated_at
38			FROM services
39			WHERE tenant_id = $1
40			ORDER BY name ASC
41		`, tenantID)
42		if err != nil {
43			return c.JSON(http.StatusInternalServerError, map[string]string{
44				"error": "Failed to fetch services",
45			})
46		}
47		defer rows.Close()
48	
49		var services []models.Service
50		for rows.Next() {
51			var s models.Service
52			err := rows.Scan(
53				&s.ID, &s.TenantID, &s.Name, &s.Description, &s.BasePriceUSD, &s.Tier,
54				&s.AfterHoursSurchPct, &s.SameDaySurchargeUSD,
55				&s.DurationMinutes, &s.IsActive, &s.Headcount, &s.RequiredTools, &s.AddOns, &s.DailyCap,
56				&s.CreatedAt, &s.UpdatedAt,
57			)
58			if err != nil {
59				return c.JSON(http.StatusInternalServerError, map[string]string{
60					"error": "Failed to scan service",
61				})
62			}
63			services = append(services, s)
64		}
65	
66		if services == nil {
67			services = []models.Service{}
68		}
69	
70		return c.JSON(http.StatusOK, services)
71	}
