111	// CreateService creates a new service in the catalog.
112	func (h *ServiceHandler) CreateService(c echo.Context) error {
113		currentUser := middleware.GetUserFromContext(c)
114		tenantID := middleware.GetTenantIDFromContext(c)
115	
116		var req models.CreateServiceRequest
117		if err := c.Bind(&req); err != nil {
118			return c.JSON(http.StatusBadRequest, map[string]string{
119				"error": "Invalid request body",
120			})
121		}
122	
123		// Validate tier
124		if req.Tier != "standard" && req.Tier != "premium" && req.Tier != "enterprise" {
125			return c.JSON(http.StatusBadRequest, map[string]string{
126				"error": "Tier must be one of: standard, premium, enterprise",
127			})
128		}
129	
130		// Validate duration: must be 15-min increment, between 15 and 240
131		if req.DurationMinutes < 15 || req.DurationMinutes > 240 || req.DurationMinutes%15 != 0 {
132			return c.JSON(http.StatusBadRequest, map[string]string{
133				"error": "Duration must be between 15 and 240 minutes in 15-minute increments",
134			})
135		}
136	
137		// Validate headcount range
138		if req.Headcount < 1 || req.Headcount > 10 {
139			return c.JSON(http.StatusBadRequest, map[string]string{
140				"error": "Headcount must be between 1 and 10",
141			})
142		}
143	
144		if req.Name == "" {
145			return c.JSON(http.StatusBadRequest, map[string]string{
146				"error": "Service name is required",
147			})
148		}
149	
150		newID := uuid.New()
151		now := time.Now()
152	
153		// Default headcount to 1 if not provided
154		headcount := req.Headcount
155		if headcount <= 0 {
156			headcount = 1
157		}
158	
159		_, err := h.DB.Exec(`
160			INSERT INTO services (id, tenant_id, name, description, base_price_usd, tier,
161			                      after_hours_surcharge_pct, same_day_surcharge_usd,
162			                      duration_minutes, is_active, headcount, required_tools, add_ons, daily_cap,
