225				return c.JSON(http.StatusBadRequest, map[string]string{
226					"error": "Headcount must be between 1 and 10",
227				})
228			}
229		}
230	
231		query := "UPDATE services SET updated_at = NOW()"
232		args := []interface{}{}
233		argIdx := 1
234	
235		if req.Name != nil {
236			query += fmt.Sprintf(", name = $%d", argIdx)
237			args = append(args, *req.Name)
238			argIdx++
239		}
240		if req.Description != nil {
