266			query += fmt.Sprintf(", duration_minutes = $%d", argIdx)
267			args = append(args, *req.DurationMinutes)
268			argIdx++
269		}
270		if req.IsActive != nil {
271			query += fmt.Sprintf(", is_active = $%d", argIdx)
