356	// GetPricing calculates the total price for a service with surcharges applied.
357	// Uses pricing_tiers table for granular duration/headcount-based pricing if configured.
358	func (h *ServiceHandler) GetPricing(c echo.Context) error {
359		tenantID := middleware.GetTenantIDFromContext(c)
360		serviceID, err := uuid.Parse(c.Param("id"))
361		if err != nil {
362			return c.JSON(http.StatusBadRequest, map[string]string{
363				"error": "Invalid service ID",
364			})
365		}
366	
367		afterHours := c.QueryParam("after_hours") == "true"
368		sameDay := c.QueryParam("same_day") == "true"
369		requestedDuration := 0
370		if d := c.QueryParam("duration"); d != "" {
371			fmt.Sscanf(d, "%d", &requestedDuration)
372		}
373		requestedHeadcount := 0
374		if h := c.QueryParam("headcount"); h != "" {
375			fmt.Sscanf(h, "%d", &requestedHeadcount)
376		}
377	
378		var s models.Service
379		err = h.DB.QueryRow(`
380			SELECT id, tenant_id, name, description, base_price_usd, tier,
381			       after_hours_surcharge_pct, same_day_surcharge_usd,
382			       duration_minutes, is_active, headcount, required_tools, add_ons, daily_cap,
383			       created_at, updated_at
384			FROM services
385			WHERE id = $1 AND tenant_id = $2
386		`, serviceID, tenantID).Scan(
387			&s.ID, &s.TenantID, &s.Name, &s.Description, &s.BasePriceUSD, &s.Tier,
388			&s.AfterHoursSurchPct, &s.SameDaySurchargeUSD,
389			&s.DurationMinutes, &s.IsActive, &s.Headcount, &s.RequiredTools, &s.AddOns, &s.DailyCap,
390			&s.CreatedAt, &s.UpdatedAt,
391		)
392		if err == sql.ErrNoRows {
393			return c.JSON(http.StatusNotFound, map[string]string{
394				"error": "Service not found",
395			})
396		}
397		if err != nil {
398			return c.JSON(http.StatusInternalServerError, map[string]string{
399				"error": "Failed to fetch service",
400			})
401		}
402	
403		// Start with base price
404		basePrice := s.BasePriceUSD
405	
406		// Check for granular duration-based pricing tier
407		duration := s.DurationMinutes
408		if requestedDuration > 0 {
409			duration = requestedDuration
410		}
411		var durationTierPrice *float64
412		_ = h.DB.QueryRow(`
413			SELECT price_usd FROM pricing_tiers
414			WHERE service_id = $1 AND tier_type = 'duration' AND $2 >= min_value AND $2 <= max_value
415			ORDER BY min_value ASC LIMIT 1
416		`, serviceID, duration).Scan(&durationTierPrice)
417		if durationTierPrice != nil {
418			basePrice = *durationTierPrice
419		}
420	
421		// Check for granular headcount-based pricing tier
422		headcount := s.Headcount
423		if requestedHeadcount > 0 {
424			headcount = requestedHeadcount
425		}
426		var headcountTierPrice *float64
427		_ = h.DB.QueryRow(`
428			SELECT price_usd FROM pricing_tiers
429			WHERE service_id = $1 AND tier_type = 'headcount' AND $2 >= min_value AND $2 <= max_value
430			ORDER BY min_value ASC LIMIT 1
431		`, serviceID, headcount).Scan(&headcountTierPrice)
432		if headcountTierPrice != nil {
433			basePrice = *headcountTierPrice
434		}
435	
436		// Tier multiplier (standard/premium/enterprise)
437		tierMultiplier := 1.0
438		switch s.Tier {
439		case "premium":
440			tierMultiplier = 1.5
441		case "enterprise":
442			tierMultiplier = 2.0
443		}
444	
445		tierAdjustedPrice := basePrice * tierMultiplier
446	
447		// After-hours surcharge
448		afterHoursSurcharge := 0.0
449		if afterHours {
450			afterHoursSurcharge = tierAdjustedPrice * (float64(s.AfterHoursSurchPct) / 100.0)
451		}
452	
453		// Same-day surcharge
454		sameDaySurcharge := 0.0
455		if sameDay {
456			sameDaySurcharge = s.SameDaySurchargeUSD
457		}
458	
459		total := tierAdjustedPrice + afterHoursSurcharge + sameDaySurcharge
460		total = math.Round(total*100) / 100
461	
462		return c.JSON(http.StatusOK, models.PricingResponse{
463			ServiceID:           s.ID,
464			ServiceName:         s.Name,
465			BasePriceUSD:        basePrice,
466			TierMultiplier:      tierMultiplier,
467			TierAdjustedPrice:   tierAdjustedPrice,
468			AfterHoursSurcharge: afterHoursSurcharge,
469			SameDaySurcharge:    sameDaySurcharge,
470			TotalUSD:            total,
471		})
472	}
