49	// StoreSensitiveData handles POST /api/security/sensitive.
50	func (h *SecurityHandler) StoreSensitiveData(c echo.Context) error {
51		user := middleware.GetUserFromContext(c)
52		if user == nil {
53			return c.JSON(http.StatusUnauthorized, map[string]string{"error": "Authentication required"})
54		}
55	
56		var req models.StoreSensitiveDataRequest
57		if err := c.Bind(&req); err != nil {
58			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
59		}
60	
61		if req.DataType == "" || req.Value == "" {
62			return c.JSON(http.StatusBadRequest, map[string]string{"error": "data_type and value are required"})
63		}
64	
65		// Use or create the default encryption key (scoped to tenant)
66		keyAlias := "default-key"
67		var keyExists bool
68		_ = h.DB.QueryRow("SELECT EXISTS(SELECT 1 FROM encryption_keys WHERE key_alias = $1 AND tenant_id = $2 AND status = 'active')", keyAlias, user.TenantID).Scan(&keyExists)
69		if !keyExists {
70			// Bootstrap the default encryption key — encrypt DEK at rest using master key (envelope encryption)
71			newKeyID := uuid.New()
72			rawKey := h.Enc.GenerateKeyBytes()
73			encKey, encNonce, encErr := h.Enc.Encrypt(rawKey)
74			if encErr != nil {
75				return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to encrypt key material"})
76			}
77			now := time.Now()
78			_, bootstrapErr := h.DB.Exec(`
79				INSERT INTO encryption_keys (id, tenant_id, key_alias, encrypted_key, nonce, algorithm, status, rotation_number, activated_at, created_at)
80				VALUES ($1, $2, $3, $4, $5, 'AES-256-GCM', 'active', 0, $6, $7)
81				ON CONFLICT (tenant_id, key_alias) DO NOTHING
82			`, newKeyID, user.TenantID, keyAlias, encKey, encNonce, now, now)
83			if bootstrapErr != nil {
84				return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to bootstrap encryption key"})
85			}
86		}
87	
88		err := h.Enc.StoreSensitiveField(h.DB, user.TenantID, user.ID, req.DataType, req.Value, req.Label, keyAlias)
89		if err != nil {
90			return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to store sensitive data"})
91		}
92	
93		h.writeAuditLog(c, "store_sensitive_data", "sensitive_data", "", map[string]interface{}{
94			"data_type": req.DataType,
95			"label":     req.Label,
96		})
97	
98		return c.JSON(http.StatusCreated, map[string]string{"message": "Sensitive data stored successfully"})
99	}
