136		resp := models.SensitiveDataResponse{
137			ID:          sd.ID,
138			DataType:    sd.DataType,
139			Label:       sd.Label,
140			MaskedValue: h.Enc.MaskValue(plaintext),
141			CreatedAt:   sd.CreatedAt,
142		}
143	
144		return c.JSON(http.StatusOK, resp)
145	}
