515				"error": "Review not found",
516			})
517		}
518		if err != nil {
519			return c.JSON(http.StatusInternalServerError, map[string]string{
520				"error": "Failed to fetch review",
521			})
522		}
523	
524		if contentTenantID != tenantID {
525			return c.JSON(http.StatusForbidden, map[string]string{
526				"error": "Access denied",
527			})
528		}
529	
530		if review.Status != "pending" {
531			return c.JSON(http.StatusBadRequest, map[string]string{
532				"error": "Review has already been decided",
533			})
534		}
535	
536		// Update the review
537		var decisionNotes *string
538		if req.DecisionNotes != "" {
539			decisionNotes = &req.DecisionNotes
540		}
541	
542		_, err = h.DB.Exec(`
543			UPDATE moderation_reviews
544			SET status = $2, reviewer_id = $3, decision_notes = $4, decided_at = NOW()
545			WHERE id = $1
546		`, reviewID, req.Decision, currentUser.ID, decisionNotes)
547		if err != nil {
548			return c.JSON(http.StatusInternalServerError, map[string]string{
549				"error": "Failed to update review",
550			})
551		}
552	
553		// Handle the decision
554		switch req.Decision {
555		case "approved":
556			// Check if there are higher-level pending reviews
557			var pendingCount int
558			_ = h.DB.QueryRow(`
559				SELECT COUNT(*) FROM moderation_reviews
560				WHERE content_id = $1 AND review_level > $2 AND status = 'pending'
561			`, review.ContentID, review.ReviewLevel).Scan(&pendingCount)
562	
563			if pendingCount == 0 {
564				// Final approval — update content to approved and start gray release
565				_, _ = h.DB.Exec(`
566					UPDATE content_items SET status = 'approved', updated_at = NOW()
567					WHERE id = $1
568				`, review.ContentID)
569	
570				// Start gray release
571				_ = services.StartGrayRelease(h.DB, review.ContentID)
572			} else {
573				// Move content to in_review for next level
574				_, _ = h.DB.Exec(`
575					UPDATE content_items SET status = 'in_review', updated_at = NOW()
576					WHERE id = $1
577				`, review.ContentID)
578			}
579	
580		case "rejected":
581			_, _ = h.DB.Exec(`
582				UPDATE content_items SET status = 'rejected', updated_at = NOW()
583				WHERE id = $1
584			`, review.ContentID)
585	
586		case "escalated":
587			// Create a higher-level review
588			nextLevel := review.ReviewLevel + 1
589			_ = services.CreateReview(h.DB, review.ContentID, uuid.Nil, nextLevel, false, "")
590	
591			_, _ = h.DB.Exec(`
592				UPDATE content_items SET status = 'in_review', updated_at = NOW()
593				WHERE id = $1
594			`, review.ContentID)
595		}
596	
597		if err := govWriteCriticalAuditLog(h.AL, h.DB, &tenantID, &currentUser.ID, "review_decision", "moderation_review", &reviewID, map[string]interface{}{
598			"decision":   req.Decision,
599			"content_id": review.ContentID,
600			"level":      review.ReviewLevel,
601		}, c.RealIP()); err != nil {
602			return c.JSON(http.StatusInternalServerError, map[string]string{
603				"error": "Audit system unavailable, action denied",
604			})
605		}
606	
607		return c.JSON(http.StatusOK, map[string]string{
608			"message": fmt.Sprintf("Review %s successfully", req.Decision),
609		})
610	}
