1046	func (h *GovernanceHandler) DiffVersions(c echo.Context) error {
1047		tenantID := middleware.GetTenantIDFromContext(c)
1048	
1049		contentID, err := uuid.Parse(c.Param("id"))
1050		if err != nil {
1051			return c.JSON(http.StatusBadRequest, map[string]string{
1052				"error": "Invalid content ID",
1053			})
1054		}
1055	
1056		v1, err := strconv.Atoi(c.QueryParam("v1"))
1057		if err != nil || v1 < 1 {
1058			return c.JSON(http.StatusBadRequest, map[string]string{
1059				"error": "v1 query parameter must be a positive integer",
1060			})
1061		}
1062		v2, err := strconv.Atoi(c.QueryParam("v2"))
1063		if err != nil || v2 < 1 {
1064			return c.JSON(http.StatusBadRequest, map[string]string{
1065				"error": "v2 query parameter must be a positive integer",
1066			})
1067		}
1068	
1069		// Verify content belongs to tenant
1070		var itemTenantID uuid.UUID
1071		err = h.DB.QueryRow(`SELECT tenant_id FROM content_items WHERE id = $1`, contentID).Scan(&itemTenantID)
1072		if err == sql.ErrNoRows {
1073			return c.JSON(http.StatusNotFound, map[string]string{
1074				"error": "Content not found",
1075			})
1076		}
1077		if err != nil {
1078			return c.JSON(http.StatusInternalServerError, map[string]string{
1079				"error": "Failed to fetch content",
1080			})
1081		}
1082		if itemTenantID != tenantID {
1083			return c.JSON(http.StatusForbidden, map[string]string{
1084				"error": "Access denied",
1085			})
1086		}
1087	
1088		// Fetch both versions
1089		var ver1, ver2 models.ContentVersion
1090		err = h.DB.QueryRow(`
1091			SELECT id, content_id, version_number, title, body, subject, grade, tags, release_notes, created_by, created_at
1092			FROM content_versions WHERE content_id = $1 AND version_number = $2
1093		`, contentID, v1).Scan(
1094			&ver1.ID, &ver1.ContentID, &ver1.VersionNumber, &ver1.Title, &ver1.Body,
1095			&ver1.Subject, &ver1.Grade, &ver1.Tags, &ver1.ReleaseNotes, &ver1.CreatedBy, &ver1.CreatedAt,
1096		)
1097		if err == sql.ErrNoRows {
1098			return c.JSON(http.StatusNotFound, map[string]string{
1099				"error": fmt.Sprintf("Version %d not found", v1),
1100			})
1101		}
1102		if err != nil {
1103			return c.JSON(http.StatusInternalServerError, map[string]string{
1104				"error": "Failed to fetch version",
1105			})
1106		}
1107	
1108		err = h.DB.QueryRow(`
1109			SELECT id, content_id, version_number, title, body, subject, grade, tags, release_notes, created_by, created_at
1110			FROM content_versions WHERE content_id = $1 AND version_number = $2
1111		`, contentID, v2).Scan(
1112			&ver2.ID, &ver2.ContentID, &ver2.VersionNumber, &ver2.Title, &ver2.Body,
1113			&ver2.Subject, &ver2.Grade, &ver2.Tags, &ver2.ReleaseNotes, &ver2.CreatedBy, &ver2.CreatedAt,
1114		)
1115		if err == sql.ErrNoRows {
1116			return c.JSON(http.StatusNotFound, map[string]string{
1117				"error": fmt.Sprintf("Version %d not found", v2),
1118			})
1119		}
1120		if err != nil {
1121			return c.JSON(http.StatusInternalServerError, map[string]string{
1122				"error": "Failed to fetch version",
1123			})
1124		}
1125	
1126		// Build diff response
1127		diff := map[string]interface{}{
1128			"content_id": contentID,
1129			"v1":         v1,
1130			"v2":         v2,
1131			"changes":    map[string]interface{}{},
1132		}
1133	
1134		changes := map[string]interface{}{}
1135		if ver1.Title != ver2.Title {
1136			changes["title"] = map[string]string{"old": ver1.Title, "new": ver2.Title}
1137		}
1138		if ver1.Body != ver2.Body {
1139			changes["body"] = map[string]string{"old": ver1.Body, "new": ver2.Body}
1140		}
1141		if ptrStrVal(ver1.Subject) != ptrStrVal(ver2.Subject) {
1142			changes["subject"] = map[string]string{"old": ptrStrVal(ver1.Subject), "new": ptrStrVal(ver2.Subject)}
1143		}
1144		if ptrStrVal(ver1.Grade) != ptrStrVal(ver2.Grade) {
1145			changes["grade"] = map[string]string{"old": ptrStrVal(ver1.Grade), "new": ptrStrVal(ver2.Grade)}
1146		}
1147	
1148		diff["changes"] = changes
1149	
1150		return c.JSON(http.StatusOK, diff)
1151	}
