1168		var req models.CreateResourceRelationshipRequest
1169		if err := c.Bind(&req); err != nil {
1170			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
1171		}
1172	
1173		if req.SourceContentID == uuid.Nil || req.TargetContentID == uuid.Nil {
1174			return c.JSON(http.StatusBadRequest, map[string]string{"error": "source_content_id and target_content_id are required"})
1175		}
1176	
1177		validTypes := map[string]bool{"dependency": true, "substitute": true, "bundle": true}
1178		if !validTypes[req.RelationshipType] {
1179			return c.JSON(http.StatusBadRequest, map[string]string{"error": "relationship_type must be one of: dependency, substitute, bundle"})
1180		}
1181	
1182		if req.SourceContentID == req.TargetContentID {
1183			return c.JSON(http.StatusBadRequest, map[string]string{"error": "source and target cannot be the same content"})
