1189		_ = h.DB.QueryRow("SELECT EXISTS(SELECT 1 FROM content_items WHERE id = $1 AND tenant_id = $2)", req.TargetContentID, tenantID).Scan(&targetExists)
1190		if !sourceExists || !targetExists {
1191			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Both source and target content items must belong to your tenant"})
1192		}
1193	
1194		newID := uuid.New()
1195		now := time.Now()
1196	
1197		_, err := h.DB.Exec(`
1198			INSERT INTO resource_relationships (id, tenant_id, source_content_id, target_content_id, relationship_type, notes, created_by, created_at)
1199			VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
1200		`, newID, tenantID, req.SourceContentID, req.TargetContentID, req.RelationshipType, req.Notes, currentUser.ID, now)
