1205		govWriteAuditLog(h.DB, &tenantID, &currentUser.ID, "create_relationship", "resource_relationship", &newID, map[string]interface{}{
1206			"source": req.SourceContentID, "target": req.TargetContentID, "type": req.RelationshipType,
