1284	// ReReview handles POST /api/governance/content/:id/re-review.
1285	func (h *GovernanceHandler) ReReview(c echo.Context) error {
1286		currentUser := middleware.GetUserFromContext(c)
1287		tenantID := middleware.GetTenantIDFromContext(c)
1288	
1289		contentID, err := uuid.Parse(c.Param("id"))
1290		if err != nil {
1291			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid content ID"})
1292		}
1293	
1294		// Get current content status
1295		var status string
1296		err = h.DB.QueryRow("SELECT status FROM content_items WHERE id = $1 AND tenant_id = $2", contentID, tenantID).Scan(&status)
1297		if err == sql.ErrNoRows {
1298			return c.JSON(http.StatusNotFound, map[string]string{"error": "Content not found"})
1299		}
1300		if err != nil {
1301			return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch content"})
1302		}
1303	
1304		// Can only re-review content that was previously approved, rejected, or published
1305		allowedStatuses := map[string]bool{"approved": true, "rejected": true, "published": true, "gray_release": true}
1306		if !allowedStatuses[status] {
1307			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Content must be approved, rejected, or published to request re-review"})
1308		}
1309	
1310		// Set status back to pending_review
1311		_, err = h.DB.Exec(`UPDATE content_items SET status = 'pending_review', updated_at = NOW() WHERE id = $1`, contentID)
1312		if err != nil {
1313			return c.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to update content status"})
1314		}
1315	
1316		// Create a new review at level 1
1317		_ = services.CreateReview(h.DB, contentID, uuid.Nil, 1, false, "Re-review requested")
1318	
1319		govWriteAuditLog(h.DB, &tenantID, &currentUser.ID, "re_review", "content_item", &contentID, map[string]interface{}{
1320			"previous_status": status,
1321		}, c.RealIP())
1322	
1323		return c.JSON(http.StatusOK, map[string]string{"message": "Content submitted for re-review"})
1324	}
