32	// govWriteAuditLog is a local helper to insert an audit log entry.
33	func govWriteAuditLog(db *sql.DB, tenantID *uuid.UUID, userID *uuid.UUID, action, resourceType string, resourceID *uuid.UUID, details map[string]interface{}, ipAddress string) {
34		id := uuid.New()
35		var detailsStr *string
36		if details != nil {
37			b, _ := json.Marshal(details)
38			s := string(b)
39			detailsStr = &s
40		}
41		_, _ = db.Exec(`
42			INSERT INTO audit_logs (id, tenant_id, user_id, action, resource_type, resource_id, details, ip_address)
43			VALUES ($1, $2, $3, $4, $5, $6, $7, $8::inet)
44		`, id, tenantID, userID, action, resourceType, resourceID, detailsStr, ipAddress)
45	}
