47	// govWriteCriticalAuditLog writes to both mutable audit_logs and immutable audit_ledger.
48	// Returns an error if the immutable ledger append fails — callers MUST treat this as a hard failure.
49	func govWriteCriticalAuditLog(al *services.AuditLedger, db *sql.DB, tenantID *uuid.UUID, userID *uuid.UUID, action, resourceType string, resourceID *uuid.UUID, details map[string]interface{}, ipAddress string) error {
50		// Write to immutable audit_ledger first — if this fails, the action must not proceed
51		resID := ""
52		if resourceID != nil {
53			resID = resourceID.String()
54		}
55		if err := al.Append(tenantID, userID, action, resourceType, resID, details, ipAddress); err != nil {
56			log.Printf("CRITICAL: immutable audit ledger append failed for action=%s: %v", action, err)
57			return fmt.Errorf("immutable audit log write failed: %w", err)
58		}
59	
60		// Also write to mutable audit_logs for general querying
61		govWriteAuditLog(db, tenantID, userID, action, resourceType, resourceID, details, ipAddress)
62		return nil
63	}
