67	// CreateContent handles POST for creating new content with auto-block check.
68	func (h *GovernanceHandler) CreateContent(c echo.Context) error {
69		currentUser := middleware.GetUserFromContext(c)
70		tenantID := middleware.GetTenantIDFromContext(c)
71	
72		var req models.CreateContentRequest
73		if err := c.Bind(&req); err != nil {
74			return c.JSON(http.StatusBadRequest, map[string]string{
75				"error": "Invalid request body",
76			})
77		}
78	
79		// Validate required fields
80		if req.Title == "" {
81			return c.JSON(http.StatusBadRequest, map[string]string{
82				"error": "title is required",
83			})
84		}
85		if req.Body == "" {
86			return c.JSON(http.StatusBadRequest, map[string]string{
87				"error": "body is required",
88			})
89		}
90	
91		// Validate content_type
92		validTypes := map[string]bool{"article": true, "resource": true, "announcement": true, "policy": true}
93		if req.ContentType == "" {
94			req.ContentType = "article"
95		}
96		if !validTypes[req.ContentType] {
97			return c.JSON(http.StatusBadRequest, map[string]string{
98				"error": "content_type must be one of: article, resource, announcement, policy",
99			})
100		}
101	
102		// Auto-block check
103		blocked, reasons, err := services.AutoBlockCheck(h.DB, tenantID, req.Title, req.Body)
104		if err != nil {
105			return c.JSON(http.StatusInternalServerError, map[string]string{
106				"error": "Failed to run moderation check",
107			})
108		}
109	
110		newID := uuid.New()
111		now := time.Now()
112		status := "draft"
113		if blocked {
114			status = "rejected"
115		}
116	
117		_, err = h.DB.Exec(`
118			INSERT INTO content_items (id, tenant_id, title, body, content_type, subject, grade, tags, status, current_version, metadata, created_by, created_at, updated_at)
119			VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9, 1, $10, $11, $12, $13)
120		`, newID, tenantID, req.Title, req.Body, req.ContentType, req.Subject, req.Grade, pq.StringArray(req.Tags), status, req.Metadata, currentUser.ID, now, now)
121		if err != nil {
122			return c.JSON(http.StatusInternalServerError, map[string]string{
123				"error": "Failed to create content",
124			})
125		}
126	
127		// Create version 1
128		_ = services.CreateVersion(h.DB, newID, currentUser.ID, "Initial version")
129	
130		// If auto-blocked, create a review record
131		if blocked {
132			reasonStr := ""
133			for i, r := range reasons {
134				if i > 0 {
135					reasonStr += "; "
136				}
137				reasonStr += r
138			}
139			_ = services.CreateReview(h.DB, newID, uuid.Nil, 1, true, reasonStr)
140		}
141	
142		govWriteAuditLog(h.DB, &tenantID, &currentUser.ID, "create_content", "content_item", &newID, map[string]interface{}{
143			"title":   req.Title,
144			"blocked": blocked,
145		}, c.RealIP())
146	
147		// Return the created content
148		if blocked {
149			return c.JSON(http.StatusCreated, map[string]interface{}{
150				"content_id":    newID,
151				"status":        status,
152				"auto_blocked":  true,
153				"block_reasons": reasons,
154			})
155		}
156	
157		return c.JSON(http.StatusCreated, map[string]interface{}{
158			"content_id": newID,
159			"status":     status,
160		})
161	}
