21	// devMasterKey is a placeholder key used only in development when MASTER_KEY is not set.
22	// It is exactly 32 bytes for AES-256.
23	var devMasterKey = []byte("CHANGE_ME_32_BYTE_DEV_KEY_00000!")
24	
25	// EncryptionService provides AES-256-GCM encryption and key management.
26	type EncryptionService struct {
27		masterKey []byte
28	}
29	
30	// NewEncryptionService creates a new EncryptionService.
31	// It tries the local keyring file first, then the MASTER_KEY environment variable (hex-encoded),
32	// and finally falls back to a development default with a warning.
33	func NewEncryptionService() *EncryptionService {
34		// Try local keyring file first
35		key := loadKeyFromKeyring()
36		if key != nil {
37			return &EncryptionService{masterKey: key}
38		}
39		// Fall back to environment variable
40		envKey := os.Getenv("MASTER_KEY")
41		if envKey != "" {
42			decoded, err := hex.DecodeString(envKey)
43			if err == nil && len(decoded) == 32 {
44				return &EncryptionService{masterKey: decoded}
45			}
46			// Also accept raw 32-byte keys for backward compatibility
47			if len(envKey) == 32 {
48				return &EncryptionService{masterKey: []byte(envKey)}
49			}
50			log.Println("WARNING: MASTER_KEY is not valid hex-encoded 32-byte key or raw 32 bytes. Using dev-mode default.")
51		}
52		// Development fallback — reject in production
53		env := os.Getenv("APP_ENV")
54		if env == "production" || env == "prod" {
55			log.Fatal("FATAL: No master key configured. Set MASTER_KEY env var or use keyring for production. Refusing to start with dev key.")
56		}
57		log.Println("WARNING: Using development master key. Set MASTER_KEY env var or use keyring for production.")
58		devKey := make([]byte, 32)
59		copy(devKey, []byte("dev-master-key-not-for-production"))
60		return &EncryptionService{masterKey: devKey}
61	}
62	
63	// loadKeyFromKeyring attempts to load a hex-encoded 32-byte master key from local keyring files.
64	func loadKeyFromKeyring() []byte {
65		paths := []string{".keyring", os.Getenv("HOME") + "/.compliance-console-keyring"}
66		for _, path := range paths {
67			data, err := os.ReadFile(path)
68			if err != nil {
69				continue
70			}
71			trimmed := strings.TrimSpace(string(data))
72			decoded, err := hex.DecodeString(trimmed)
73			if err == nil && len(decoded) == 32 {
74				log.Printf("Loaded master key from keyring file: %s", path)
75				return decoded
76			}
77		}
78		return nil
79	}
80	
81	// Encrypt encrypts plaintext using AES-256-GCM and returns ciphertext and nonce.
82	func (s *EncryptionService) Encrypt(plaintext []byte) (ciphertext []byte, nonce []byte, err error) {
83		block, err := aes.NewCipher(s.masterKey)
84		if err != nil {
85			return nil, nil, fmt.Errorf("failed to create cipher: %w", err)
86		}
87	
88		gcm, err := cipher.NewGCM(block)
89		if err != nil {
90			return nil, nil, fmt.Errorf("failed to create GCM: %w", err)
91		}
92	
93		nonce = make([]byte, gcm.NonceSize()) // 12 bytes for GCM
94		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
95			return nil, nil, fmt.Errorf("failed to generate nonce: %w", err)
96		}
97	
98		ciphertext = gcm.Seal(nil, nonce, plaintext, nil)
99		return ciphertext, nonce, nil
100	}
101	
102	// Decrypt decrypts ciphertext using AES-256-GCM with the provided nonce.
103	func (s *EncryptionService) Decrypt(ciphertext, nonce []byte) ([]byte, error) {
104		block, err := aes.NewCipher(s.masterKey)
105		if err != nil {
106			return nil, fmt.Errorf("failed to create cipher: %w", err)
107		}
108	
109		gcm, err := cipher.NewGCM(block)
110		if err != nil {
111			return nil, fmt.Errorf("failed to create GCM: %w", err)
112		}
113	
114		plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
115		if err != nil {
116			return nil, fmt.Errorf("failed to decrypt: %w", err)
117		}
118	
119		return plaintext, nil
120	}
121	
122	// decryptDEK retrieves and decrypts the data-encryption key (DEK) for a given alias and tenant.
123	// Returns the raw 32-byte DEK or an error.
124	func (s *EncryptionService) decryptDEK(db *sql.DB, tenantID uuid.UUID, keyAlias string) ([]byte, error) {
125		var encryptedKey, nonce []byte
126		err := db.QueryRow(`
127			SELECT encrypted_key, nonce FROM encryption_keys
128			WHERE key_alias = $1 AND tenant_id = $2 AND status = 'active'
129		`, keyAlias, tenantID).Scan(&encryptedKey, &nonce)
130		if err != nil {
131			return nil, fmt.Errorf("failed to retrieve DEK for alias %s: %w", keyAlias, err)
132		}
133	
134		// If nonce is nil, the key was bootstrapped before envelope encryption was added.
135		// Cannot decrypt the DEK without its nonce — caller should fall back to master key.
136		if nonce == nil {
137			return nil, fmt.Errorf("DEK for alias %s has no nonce (legacy key without envelope encryption)", keyAlias)
138		}
139	
140		dek, err := s.Decrypt(encryptedKey, nonce)
141		if err != nil {
142			return nil, fmt.Errorf("failed to decrypt DEK for alias %s: %w", keyAlias, err)
143		}
144		return dek, nil
145	}
