147	// encryptWithKey encrypts plaintext using a specific key (not the master key).
148	func encryptWithKey(key, plaintext []byte) (ciphertext []byte, nonce []byte, err error) {
149		block, err := aes.NewCipher(key)
150		if err != nil {
151			return nil, nil, fmt.Errorf("failed to create cipher: %w", err)
152		}
153		gcm, err := cipher.NewGCM(block)
154		if err != nil {
155			return nil, nil, fmt.Errorf("failed to create GCM: %w", err)
156		}
157		nonce = make([]byte, gcm.NonceSize())
158		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
159			return nil, nil, fmt.Errorf("failed to generate nonce: %w", err)
160		}
161		ciphertext = gcm.Seal(nil, nonce, plaintext, nil)
162		return ciphertext, nonce, nil
163	}
164	
165	// decryptWithKey decrypts ciphertext using a specific key (not the master key).
166	func decryptWithKey(key, ciphertext, nonce []byte) ([]byte, error) {
167		block, err := aes.NewCipher(key)
168		if err != nil {
169			return nil, fmt.Errorf("failed to create cipher: %w", err)
170		}
171		gcm, err := cipher.NewGCM(block)
172		if err != nil {
173			return nil, fmt.Errorf("failed to create GCM: %w", err)
174		}
175		plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
176		if err != nil {
177			return nil, fmt.Errorf("failed to decrypt: %w", err)
178		}
179		return plaintext, nil
180	}
