182	// DecryptValue decrypts ciphertext using the DEK identified by keyAlias (envelope decryption).
183	// Falls back to master key if no DEK is registered for backward compatibility.
184	func (s *EncryptionService) DecryptValue(db *sql.DB, tenantID uuid.UUID, keyAlias string, ciphertext, nonce []byte) ([]byte, error) {
185		dek, dekErr := s.decryptDEK(db, tenantID, keyAlias)
186		if dekErr != nil {
187			// Fallback to master key for backward compatibility
188			return s.Decrypt(ciphertext, nonce)
189		}
190		return decryptWithKey(dek, ciphertext, nonce)
191	}
