193	// StoreSensitiveField encrypts and stores a sensitive value in the sensitive_data table.
194	// Uses envelope encryption: retrieves the DEK by alias, encrypts data with the DEK.
195	// Falls back to master key if no DEK is registered (backward compatibility).
196	func (s *EncryptionService) StoreSensitiveField(db *sql.DB, tenantID, ownerID uuid.UUID, dataType, value, label, keyAlias string) error {
197		var ciphertext, nonce []byte
198		var err error
199	
200		dek, dekErr := s.decryptDEK(db, tenantID, keyAlias)
201		if dekErr != nil {
202			// Fallback to master key for backward compatibility (no DEK registered yet)
203			ciphertext, nonce, err = s.Encrypt([]byte(value))
204		} else {
205			ciphertext, nonce, err = encryptWithKey(dek, []byte(value))
206		}
207		if err != nil {
208			return fmt.Errorf("encryption failed: %w", err)
209		}
210	
211		_, err = db.Exec(`
212			INSERT INTO sensitive_data (tenant_id, owner_id, data_type, encrypted_value, nonce, key_alias, label)
213			VALUES ($1, $2, $3, $4, $5, $6, $7)
214		`, tenantID, ownerID, dataType, ciphertext, nonce, keyAlias, label)
215		if err != nil {
216			return fmt.Errorf("failed to store sensitive data: %w", err)
217		}
218	
219		return nil
220	}
