222	// RetrieveSensitiveField decrypts and returns the plaintext value for a sensitive_data record.
223	// Uses envelope decryption: retrieves the DEK by alias, decrypts data with the DEK.
224	// Falls back to master key if no DEK is registered (backward compatibility).
225	func (s *EncryptionService) RetrieveSensitiveField(db *sql.DB, id uuid.UUID, tenantID uuid.UUID) (string, error) {
226		var encryptedValue, nonce []byte
227		var keyAlias string
228		err := db.QueryRow(`
229			SELECT encrypted_value, nonce, key_alias FROM sensitive_data WHERE id = $1 AND tenant_id = $2
230		`, id, tenantID).Scan(&encryptedValue, &nonce, &keyAlias)
231		if err != nil {
232			return "", fmt.Errorf("failed to retrieve sensitive data: %w", err)
233		}
234	
235		// Try envelope decryption with DEK first
236		dek, dekErr := s.decryptDEK(db, tenantID, keyAlias)
237		var plaintext []byte
238		if dekErr != nil {
239			// Fallback: try master key directly (data encrypted before envelope encryption was enabled)
240			plaintext, err = s.Decrypt(encryptedValue, nonce)
241		} else {
242			plaintext, err = decryptWithKey(dek, encryptedValue, nonce)
243		}
244		if err != nil {
245			return "", fmt.Errorf("decryption failed: %w", err)
246		}
247	
248		return string(plaintext), nil
249	}
