753			if err := rows.Scan(&r.id, &r.txID, &r.matchID, &r.exType, &r.severity,
754				&r.amount, &r.varianceAmt, &r.description, &r.assignedTo, &r.status,
755				&r.disposition, &r.resNotes, &r.resolvedBy, &r.resolvedAt, &r.createdAt); err != nil {
756				continue
757			}
758			exRows = append(exRows, r)
759		}
760	
761		if format == "xlsx" {
762			f := excelize.NewFile()
763			sheet := "Exceptions"
764			f.SetSheetName("Sheet1", sheet)
765	
766			// Headers
767			headers := []string{"ID", "Transaction ID", "Match ID", "Type", "Severity",
768				"Amount", "Variance", "Description", "Assigned To", "Status",
769				"Disposition", "Resolution Notes", "Resolved By", "Resolved At", "Created At"}
770			for i, h := range headers {
771				cell, _ := excelize.CoordinatesToCellName(i+1, 1)
772				f.SetCellValue(sheet, cell, h)
773			}
774	
775			// Data rows
776			for rowIdx, r := range exRows {
777				rowNum := rowIdx + 2
778				vals := []string{
779					r.id.String(),
780					ptrUUIDStr(r.txID),
781					ptrUUIDStr(r.matchID),
