791					ptrUUIDStr(r.resolvedBy),
792					ptrTimeStr(r.resolvedAt),
793					r.createdAt.Format(time.RFC3339),
794				}
795				for colIdx, val := range vals {
796					cell, _ := excelize.CoordinatesToCellName(colIdx+1, rowNum)
797					f.SetCellValue(sheet, cell, val)
