799			}
800	
801			c.Response().Header().Set("Content-Type", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
802			c.Response().Header().Set("Content-Disposition", "attachment; filename=exceptions.xlsx")
803	
804			detailsJSON, _ := json.Marshal(map[string]interface{}{
805				"format": format,
806			})
807			details := string(detailsJSON)
808			writeAuditLog(h.DB, &tenantID, &currentUser.ID, "export_exceptions", "reconciliation_exception", nil, &details, c.RealIP())
809	
810			return f.Write(c.Response().Writer)
811		}
812	
813		// CSV export
814		c.Response().Header().Set("Content-Type", "text/csv")
815		c.Response().Header().Set("Content-Disposition", "attachment; filename=exceptions_export.csv")
816		c.Response().WriteHeader(http.StatusOK)
817	
818		writer := csv.NewWriter(c.Response().Writer)
819		defer writer.Flush()
820	
821		// Write header
822		_ = writer.Write([]string{
823			"id", "transaction_id", "match_id", "exception_type", "severity",
824			"amount", "variance_amount", "description", "assigned_to", "status",
825			"disposition", "resolution_notes", "resolved_by", "resolved_at", "created_at",
826		})
827	
828		for _, r := range exRows {
