858	// mapCSVColumns maps column names from the CSV header to their indices.
859	func mapCSVColumns(header []string) map[string]int {
860		m := map[string]int{
861			"date":                 -1,
862			"amount":               -1,
863			"counterparty":         -1,
864			"counterparty_account": -1,
865			"memo":                 -1,
866			"reference":            -1,
867		}
868		for i, col := range header {
869			normalized := strings.TrimSpace(strings.ToLower(col))
870			switch normalized {
871			case "date", "transaction_date", "txn_date":
872				m["date"] = i
873			case "amount", "value", "total":
874				m["amount"] = i
875			case "counterparty", "party", "vendor", "payee":
876				m["counterparty"] = i
877			case "memo", "description", "note", "notes":
878				m["memo"] = i
879			case "reference", "reference_number", "ref", "ref_number":
880				m["reference"] = i
881			case "counterparty_account", "account", "account_number", "acct", "account_no":
882				m["counterparty_account"] = i
883			}
884		}
885		return m
886	}
