896	// parseFlexibleDate attempts to parse a date string using common formats.
897	func parseFlexibleDate(s string) (time.Time, error) {
898		formats := []string{
899			time.RFC3339,
900			"2006-01-02T15:04:05",
901			"2006-01-02 15:04:05",
902			"2006-01-02",
903			"01/02/2006",
904			"1/2/2006",
905			"01-02-2006",
906			"Jan 2, 2006",
907		}
908		s = strings.TrimSpace(s)
909		for _, f := range formats {
910			if t, err := time.Parse(f, s); err == nil {
911				return t, nil
912			}
913		}
914		return time.Time{}, fmt.Errorf("unrecognized date format: %s", s)
915	}
916	
917	// ptrStr converts a *string to a string, returning empty string for nil.
918	func ptrStr(s *string) string {
919		if s == nil {
920			return ""
921		}
922		return *s
923	}
924	
925	// ptrUUIDStr converts a *uuid.UUID to a string, returning empty string for nil.
926	func ptrUUIDStr(u *uuid.UUID) string {
927		if u == nil {
928			return ""
929		}
930		return u.String()
931	}
932	
933	// ptrFloatStr converts a *float64 to a string, returning empty string for nil.
934	func ptrFloatStr(f *float64) string {
935		if f == nil {
936			return ""
937		}
938		return strconv.FormatFloat(*f, 'f', 2, 64)
939	}
940	
941	// ptrTimeStr converts a *time.Time to an RFC3339 string, returning empty string for nil.
942	func ptrTimeStr(t *time.Time) string {
943		if t == nil {
944			return ""
945		}
946		return t.Format(time.RFC3339)
947	}
