949	// parseXLSXFile parses an xlsx file and returns transaction records.
950	func parseXLSXFile(reader io.Reader) ([]models.Transaction, error) {
951		f, err := excelize.OpenReader(reader)
952		if err != nil {
953			return nil, fmt.Errorf("failed to open xlsx: %w", err)
954		}
955		defer f.Close()
956	
957		// Get the first sheet
958		sheetName := f.GetSheetName(0)
959		if sheetName == "" {
960			return nil, fmt.Errorf("no sheets found in xlsx file")
961		}
962	
963		rows, err := f.GetRows(sheetName)
964		if err != nil {
965			return nil, fmt.Errorf("failed to read rows: %w", err)
966		}
967	
968		if len(rows) < 2 {
969			return nil, fmt.Errorf("xlsx file must have a header row and at least one data row")
970		}
971	
972		// Map header columns
973		colIdx := mapCSVColumns(rows[0])
974		if colIdx["date"] < 0 || colIdx["amount"] < 0 {
975			return nil, fmt.Errorf("xlsx must contain at least 'date' and 'amount' columns")
976		}
977	
978		var records []models.Transaction
979		for i, row := range rows[1:] {
980			lineNum := i + 2
981	
982			dateStr := getCSVField(row, colIdx["date"])
983			if dateStr == "" {
984				continue
985			}
986			txDate, err := parseFlexibleDate(dateStr)
987			if err != nil {
988				return nil, fmt.Errorf("invalid date at row %d: %w", lineNum, err)
989			}
990	
991			amountStr := strings.TrimSpace(getCSVField(row, colIdx["amount"]))
992			if amountStr == "" {
993				continue
994			}
995			amount, err := strconv.ParseFloat(amountStr, 64)
996			if err != nil {
997				return nil, fmt.Errorf("invalid amount at row %d: %w", lineNum, err)
998			}
