34	// ImportFeed handles POST /api/reconciliation/import.
35	// Accepts a multipart file upload (CSV) and imports transactions.
36	func (h *ReconciliationHandler) ImportFeed(c echo.Context) error {
37		currentUser := middleware.GetUserFromContext(c)
38		tenantID := middleware.GetTenantIDFromContext(c)
39	
40		feedType := c.FormValue("feed_type")
41		if feedType != "internal" && feedType != "external" {
42			return c.JSON(http.StatusBadRequest, map[string]string{
43				"error": "feed_type must be 'internal' or 'external'",
44			})
45		}
46	
47		file, err := c.FormFile("file")
48		if err != nil {
49			return c.JSON(http.StatusBadRequest, map[string]string{
50				"error": "File upload required",
51			})
52		}
53	
54		ext := strings.ToLower(filepath.Ext(file.Filename))
55		if ext == ".xls" {
56			return c.JSON(http.StatusBadRequest, map[string]string{
57				"error": "Legacy .xls format is not supported. Please save as .xlsx or .csv (File > Save As > CSV) for import.",
58			})
59		}
60		if ext != ".csv" && ext != ".xlsx" {
61			return c.JSON(http.StatusBadRequest, map[string]string{
62				"error": "Only CSV and XLSX files are supported",
63			})
64		}
65	
66		src, err := file.Open()
67		if err != nil {
68			return c.JSON(http.StatusInternalServerError, map[string]string{
69				"error": "Failed to open uploaded file",
70			})
71		}
72		defer src.Close()
73	
74		var records []models.Transaction
75	
76		if ext == ".xlsx" {
77			records, err = parseXLSXFile(src)
78			if err != nil {
79				return c.JSON(http.StatusBadRequest, map[string]string{
80					"error": "Failed to parse XLSX: " + err.Error(),
81				})
82			}
83		} else {
84			// Parse CSV: expected columns: date, amount, counterparty, memo, reference
85			reader := csv.NewReader(src)
86	
87			// Read and validate header
88			header, err := reader.Read()
89			if err != nil {
90				return c.JSON(http.StatusBadRequest, map[string]string{
91					"error": "Failed to read CSV header",
92				})
93			}
94	
95			colIdx := mapCSVColumns(header)
96			if colIdx["date"] < 0 || colIdx["amount"] < 0 {
97				return c.JSON(http.StatusBadRequest, map[string]string{
98					"error": "CSV must contain at least 'date' and 'amount' columns",
99				})
100			}
101	
102			lineNum := 1
103			for {
104				row, err := reader.Read()
105				if err == io.EOF {
106					break
107				}
108				if err != nil {
109					return c.JSON(http.StatusBadRequest, map[string]string{
110						"error": fmt.Sprintf("Failed to parse CSV at line %d: %s", lineNum+1, err.Error()),
111					})
112				}
113				lineNum++
114	
115				txDate, err := parseFlexibleDate(getCSVField(row, colIdx["date"]))
116				if err != nil {
117					return c.JSON(http.StatusBadRequest, map[string]string{
118						"error": fmt.Sprintf("Invalid date at line %d: %s", lineNum, err.Error()),
119					})
120				}
121	
122				amountStr := strings.TrimSpace(getCSVField(row, colIdx["amount"]))
123				amount, err := strconv.ParseFloat(amountStr, 64)
124				if err != nil {
125					return c.JSON(http.StatusBadRequest, map[string]string{
126						"error": fmt.Sprintf("Invalid amount at line %d: %s", lineNum, err.Error()),
127					})
128				}
129	
130				tx := models.Transaction{
131					TransactionDate: txDate,
132					Amount:          amount,
133				}
134	
135				if cp := getCSVField(row, colIdx["counterparty"]); cp != "" {
136					tx.Counterparty = &cp
137				}
138				if acct := getCSVField(row, colIdx["counterparty_account"]); acct != "" {
139					tx.CounterpartyAccount = &acct
140				}
141				if memo := getCSVField(row, colIdx["memo"]); memo != "" {
142					tx.Memo = &memo
143				}
144				if ref := getCSVField(row, colIdx["reference"]); ref != "" {
145					tx.ReferenceNumber = &ref
146				}
147	
148				records = append(records, tx)
149			}
150		}
151	
152		if len(records) == 0 {
153			return c.JSON(http.StatusBadRequest, map[string]string{
154				"error": "File contains no data rows",
155			})
156		}
157	
158		feed, err := services.ImportCSVFeed(h.DB, tenantID, currentUser.ID, feedType, file.Filename, records)
159		if err != nil {
160			return c.JSON(http.StatusInternalServerError, map[string]string{
161				"error": "Failed to import feed: " + err.Error(),
162			})
163		}
164	
165		result := models.ImportResult{
166			FeedID:          feed.ID,
167			RecordsImported: feed.RecordCount,
168		}
169	
170		detailsJSON, _ := json.Marshal(map[string]interface{}{
171			"filename":    file.Filename,
172			"feed_type":   feedType,
173			"record_count": feed.RecordCount,
174		})
175		details := string(detailsJSON)
176		writeAuditLog(h.DB, &tenantID, &currentUser.ID, "import_feed", "transaction_feed", &feed.ID, &details, c.RealIP())
177	
178		return c.JSON(http.StatusCreated, result)
179	}
