181	// ListFeeds handles GET /api/reconciliation/feeds.
182	func (h *ReconciliationHandler) ListFeeds(c echo.Context) error {
183		tenantID := middleware.GetTenantIDFromContext(c)
184	
185		page, _ := strconv.Atoi(c.QueryParam("page"))
186		if page < 1 {
187			page = 1
188		}
189		perPage, _ := strconv.Atoi(c.QueryParam("per_page"))
190		if perPage < 1 || perPage > 100 {
191			perPage = 25
192		}
193		offset := (page - 1) * perPage
194	
195		var total int
196		err := h.DB.QueryRow("SELECT COUNT(*) FROM transaction_feeds WHERE tenant_id = $1", tenantID).Scan(&total)
197		if err != nil {
198			return c.JSON(http.StatusInternalServerError, map[string]string{
199				"error": "Failed to count feeds",
200			})
201		}
202	
203		rows, err := h.DB.Query(`
204			SELECT id, tenant_id, filename, feed_type, record_count, imported_by, imported_at, status
205			FROM transaction_feeds
206			WHERE tenant_id = $1
207			ORDER BY imported_at DESC
208			LIMIT $2 OFFSET $3
209		`, tenantID, perPage, offset)
210		if err != nil {
211			return c.JSON(http.StatusInternalServerError, map[string]string{
212				"error": "Failed to fetch feeds",
213			})
214		}
215		defer rows.Close()
216	
217		var feeds []models.TransactionFeed
218		for rows.Next() {
219			var f models.TransactionFeed
220			if err := rows.Scan(&f.ID, &f.TenantID, &f.Filename, &f.FeedType,
221				&f.RecordCount, &f.ImportedBy, &f.ImportedAt, &f.Status); err != nil {
222				return c.JSON(http.StatusInternalServerError, map[string]string{
223					"error": "Failed to scan feed",
224				})
225			}
226			feeds = append(feeds, f)
227		}
228		if feeds == nil {
229			feeds = []models.TransactionFeed{}
230		}
231	
232		totalPages := (total + perPage - 1) / perPage
233	
234		return c.JSON(http.StatusOK, map[string]interface{}{
235			"data":        feeds,
236			"page":        page,
237			"per_page":    perPage,
238			"total":       total,
239			"total_pages": totalPages,
240		})
241	}
