291			})
292		}
293	
294		// Verify feed exists and belongs to tenant
295		var feedStatus string
296		err = h.DB.QueryRow(`
297			SELECT status FROM transaction_feeds WHERE id = $1 AND tenant_id = $2
298		`, feedID, tenantID).Scan(&feedStatus)
