306				"error": "Failed to fetch feed",
307			})
308		}
309	
310		// Update feed status to processing
311		_, err = h.DB.Exec(`UPDATE transaction_feeds SET status = 'processing' WHERE id = $1`, feedID)
312		if err != nil {
313			return c.JSON(http.StatusInternalServerError, map[string]string{
