337	// GetMatchResults handles GET /api/reconciliation/matches.
338	func (h *ReconciliationHandler) GetMatchResults(c echo.Context) error {
339		tenantID := middleware.GetTenantIDFromContext(c)
340	
341		query := `
342			SELECT id, tenant_id, internal_tx_id, external_tx_id, match_confidence,
343				match_method, amount_variance, time_variance_minutes, matched_by,
344				matched_at, status
345			FROM transaction_matches
346			WHERE tenant_id = $1
347		`
348		args := []interface{}{tenantID}
349		argIdx := 2
350	
351		if feedID := c.QueryParam("feed_id"); feedID != "" {
352			query += fmt.Sprintf(`
353				AND (internal_tx_id IN (SELECT id FROM transactions WHERE feed_id = $%d)
354				     OR external_tx_id IN (SELECT id FROM transactions WHERE feed_id = $%d))
355			`, argIdx, argIdx)
356			args = append(args, feedID)
357			argIdx++
358		}
359	
360		query += " ORDER BY matched_at DESC"
361	
362		rows, err := h.DB.Query(query, args...)
363		if err != nil {
364			return c.JSON(http.StatusInternalServerError, map[string]string{
365				"error": "Failed to fetch matches",
366			})
367		}
368		defer rows.Close()
369	
370		var matches []models.TransactionMatch
371		for rows.Next() {
