195	// ListSchedules returns schedules with optional filters.
196	func (h *ScheduleHandler) ListSchedules(c echo.Context) error {
197		tenantID := middleware.GetTenantIDFromContext(c)
198	
199		query := `
200			SELECT id, tenant_id, service_id, staff_id, client_name,
201			       scheduled_start, scheduled_end, status,
202			       requires_confirmation, confirmed_at, reassignment_reason,
203			       reassignment_reason_code, pending_staff_id, created_at, updated_at
204			FROM schedules
205			WHERE tenant_id = $1
206		`
207		args := []interface{}{tenantID}
208		argIdx := 2
209	
210		// Filter by date range
211		if startDate := c.QueryParam("start_date"); startDate != "" {
212			query += fmt.Sprintf(" AND scheduled_start >= $%d", argIdx)
213			args = append(args, startDate)
214			argIdx++
215		}
216		if endDate := c.QueryParam("end_date"); endDate != "" {
217			query += fmt.Sprintf(" AND scheduled_start < ($%d::date + interval '1 day')", argIdx)
218			args = append(args, endDate)
219			argIdx++
220		}
221	
222		// Filter by staff
223		if staffID := c.QueryParam("staff_id"); staffID != "" {
224			query += fmt.Sprintf(" AND staff_id = $%d", argIdx)
225			args = append(args, staffID)
226			argIdx++
227		}
228	
229		// Filter by status
230		if status := c.QueryParam("status"); status != "" {
231			query += fmt.Sprintf(" AND status = $%d", argIdx)
232			args = append(args, status)
233			argIdx++
234		}
235	
236		query += " ORDER BY scheduled_start ASC"
237	
238		rows, err := h.DB.Query(query, args...)
239		if err != nil {
240			return c.JSON(http.StatusInternalServerError, map[string]string{
241				"error": "Failed to fetch schedules",
242			})
243		}
244		defer rows.Close()
245	
246		var schedules []models.Schedule
247		for rows.Next() {
248			var s models.Schedule
249			err := rows.Scan(
250				&s.ID, &s.TenantID, &s.ServiceID, &s.StaffID, &s.ClientName,
251				&s.ScheduledStart, &s.ScheduledEnd, &s.Status,
252				&s.RequiresConfirmation, &s.ConfirmedAt, &s.ReassignmentReason,
253				&s.ReassignmentReasonCode, &s.PendingStaffID, &s.CreatedAt, &s.UpdatedAt,
254			)
255			if err != nil {
256				return c.JSON(http.StatusInternalServerError, map[string]string{
257					"error": "Failed to scan schedule",
258				})
259			}
260			schedules = append(schedules, s)
261		}
262	
263		if schedules == nil {
264			schedules = []models.Schedule{}
265		}
266	
267		return c.JSON(http.StatusOK, schedules)
268	}
