270	// UpdateSchedule modifies an existing schedule.
271	func (h *ScheduleHandler) UpdateSchedule(c echo.Context) error {
272		currentUser := middleware.GetUserFromContext(c)
273		tenantID := middleware.GetTenantIDFromContext(c)
274	
275		scheduleID, err := uuid.Parse(c.Param("id"))
276		if err != nil {
277			return c.JSON(http.StatusBadRequest, map[string]string{
278				"error": "Invalid schedule ID",
279			})
280		}
281	
282		var req models.UpdateScheduleRequest
283		if err := c.Bind(&req); err != nil {
284			return c.JSON(http.StatusBadRequest, map[string]string{
285				"error": "Invalid request body",
286			})
287		}
288	
289		// ABAC: Resolve the schedule's current location and enforce location gate on ALL mutations
290		if currentUser.LocationID != nil {
291			var scheduleStaffLocationID *uuid.UUID
292			_ = h.DB.QueryRow(`
293				SELECT u.location_id FROM schedules s
294				JOIN staff_roster sr ON s.staff_id = sr.id
295				JOIN users u ON sr.user_id = u.id
296				WHERE s.id = $1 AND s.tenant_id = $2
297			`, scheduleID, tenantID).Scan(&scheduleStaffLocationID)
298			if scheduleStaffLocationID != nil && *scheduleStaffLocationID != *currentUser.LocationID {
299				return c.JSON(http.StatusForbidden, map[string]string{
300					"error": "Cannot modify schedules outside your assigned location",
301				})
302			}
303		}
304	
305		// If staff or time is changing, check for conflicts
306		if req.StaffID != nil || req.ScheduledStart != nil || req.ScheduledEnd != nil {
307			// Fetch existing schedule
308			var existing models.Schedule
309			err := h.DB.QueryRow(`
310				SELECT id, staff_id, scheduled_start, scheduled_end
311				FROM schedules WHERE id = $1 AND tenant_id = $2
312			`, scheduleID, tenantID).Scan(
313				&existing.ID, &existing.StaffID, &existing.ScheduledStart, &existing.ScheduledEnd,
314			)
315			if err == sql.ErrNoRows {
316				return c.JSON(http.StatusNotFound, map[string]string{
317					"error": "Schedule not found",
318				})
319			}
320			if err != nil {
321				return c.JSON(http.StatusInternalServerError, map[string]string{
322					"error": "Failed to fetch schedule",
323				})
324			}
325	
326			staffID := existing.StaffID
327			start := existing.ScheduledStart
328			end := existing.ScheduledEnd
329	
330			if req.StaffID != nil {
331				staffID = *req.StaffID
332				// ABAC: Enforce location restriction on staff reassignment
333				if currentUser.LocationID != nil {
334					var staffUserLocationID *uuid.UUID
335					_ = h.DB.QueryRow(`
336						SELECT u.location_id FROM staff_roster sr
337						JOIN users u ON sr.user_id = u.id
338						WHERE sr.id = $1 AND sr.tenant_id = $2
339					`, staffID, tenantID).Scan(&staffUserLocationID)
340					if staffUserLocationID != nil && *staffUserLocationID != *currentUser.LocationID {
341						return c.JSON(http.StatusForbidden, map[string]string{
342							"error": "Staff member is not in your assigned location",
343						})
344					}
345				}
346	
347				// Enforce mandatory reassignment reason code when staff is being changed
348				if req.ReassignmentReasonCode == nil || *req.ReassignmentReasonCode == "" {
349					return c.JSON(http.StatusBadRequest, map[string]string{
350						"error": "reassignment_reason_code is required when changing staff assignment",
351					})
352				}
353				validReasonCodes := map[string]bool{"sick_leave": true, "emergency": true, "no_show": true, "schedule_conflict": true, "requested": true, "skill_mismatch": true, "other": true}
354				if !validReasonCodes[*req.ReassignmentReasonCode] {
355					return c.JSON(http.StatusBadRequest, map[string]string{
356						"error": "Invalid reassignment_reason_code",
357					})
358				}
359			}
360			if req.ScheduledStart != nil {
361				start = *req.ScheduledStart
362			}
363			if req.ScheduledEnd != nil {
364				end = *req.ScheduledEnd
365			}
366	
367			// Check conflicts excluding the current schedule
368			hasConflict, conflicting, err := h.Scheduler.CheckConflictsExcluding(tenantID, staffID, start, end, scheduleID)
369			if err != nil {
370				return c.JSON(http.StatusInternalServerError, map[string]string{
371					"error": "Failed to check conflicts",
372				})
373			}
374			if hasConflict {
375				return c.JSON(http.StatusConflict, map[string]interface{}{
376					"error":                "Scheduling conflict detected",
377					"conflicting_schedule": conflicting,
378				})
379			}
380		}
381	
382		// Determine if this is a staff reassignment (requires confirmation workflow)
383		isReassignment := req.StaffID != nil
384	
385		query := "UPDATE schedules SET updated_at = NOW()"
386		args := []interface{}{}
387		argIdx := 1
388	
389		if req.ServiceID != nil {
390			// Validate that the new service exists, belongs to the tenant, and is active
391			var serviceExists bool
392			err := h.DB.QueryRow("SELECT EXISTS(SELECT 1 FROM services WHERE id = $1 AND tenant_id = $2 AND is_active = TRUE)", *req.ServiceID, tenantID).Scan(&serviceExists)
393			if err != nil || !serviceExists {
394				return c.JSON(http.StatusBadRequest, map[string]string{
395					"error": "Service not found or inactive",
396				})
397			}
398			query += fmt.Sprintf(", service_id = $%d", argIdx)
399			args = append(args, *req.ServiceID)
400			argIdx++
401		}
402		if isReassignment {
403			// Staff reassignment: store as pending, don't swap staff_id yet
404			query += fmt.Sprintf(", pending_staff_id = $%d", argIdx)
405			args = append(args, *req.StaffID)
406			argIdx++
407			query += fmt.Sprintf(", status = $%d", argIdx)
408			args = append(args, "pending_reassignment")
409			argIdx++
410			query += ", requires_confirmation = TRUE"
411		}
412		if req.ClientName != nil {
413			query += fmt.Sprintf(", client_name = $%d", argIdx)
414			args = append(args, *req.ClientName)
415			argIdx++
416		}
417		if req.ScheduledStart != nil {
418			query += fmt.Sprintf(", scheduled_start = $%d", argIdx)
419			args = append(args, *req.ScheduledStart)
420			argIdx++
421		}
422		if req.ScheduledEnd != nil {
423			query += fmt.Sprintf(", scheduled_end = $%d", argIdx)
424			args = append(args, *req.ScheduledEnd)
425			argIdx++
426		}
427		if req.Status != nil && !isReassignment {
428			query += fmt.Sprintf(", status = $%d", argIdx)
429			args = append(args, *req.Status)
430			argIdx++
431		}
432		if req.ReassignmentReason != nil {
433			query += fmt.Sprintf(", reassignment_reason = $%d", argIdx)
434			args = append(args, *req.ReassignmentReason)
435			argIdx++
436		}
437		if req.ReassignmentReasonCode != nil {
438			query += fmt.Sprintf(", reassignment_reason_code = $%d", argIdx)
439			args = append(args, *req.ReassignmentReasonCode)
440			argIdx++
441		}
442	
443		query += fmt.Sprintf(" WHERE id = $%d AND tenant_id = $%d", argIdx, argIdx+1)
444		args = append(args, scheduleID, tenantID)
445	
446		result, err := h.DB.Exec(query, args...)
447		if err != nil {
448			return c.JSON(http.StatusInternalServerError, map[string]string{
449				"error": "Failed to update schedule",
450			})
451		}
452	
453		rowsAffected, _ := result.RowsAffected()
454		if rowsAffected == 0 {
455			return c.JSON(http.StatusNotFound, map[string]string{
456				"error": "Schedule not found",
457			})
458		}
459	
460		detailsJSON, _ := json.Marshal(req)
461		details := string(detailsJSON)
462		writeAuditLog(h.DB, &tenantID, &currentUser.ID, "update_schedule", "schedule", &scheduleID, &details, c.RealIP())
463	
464		return h.getScheduleByID(c, scheduleID, tenantID, http.StatusOK)
465	}
