523	// ConfirmAssignment confirms a staff assignment for a schedule.
524	func (h *ScheduleHandler) ConfirmAssignment(c echo.Context) error {
525		currentUser := middleware.GetUserFromContext(c)
526		tenantID := middleware.GetTenantIDFromContext(c)
527	
528		scheduleID, err := uuid.Parse(c.Param("id"))
529		if err != nil {
530			return c.JSON(http.StatusBadRequest, map[string]string{
531				"error": "Invalid schedule ID",
532			})
533		}
534	
535		// Fetch schedule to determine confirmation type (new assignment vs reassignment)
536		var assignedStaffUserID uuid.UUID
537		var scheduleStatus string
538		var pendingStaffID *uuid.UUID
539		err = h.DB.QueryRow(`
540			SELECT sr.user_id, s.status, s.pending_staff_id FROM schedules s
541			JOIN staff_roster sr ON s.staff_id = sr.id
542			WHERE s.id = $1 AND s.tenant_id = $2
543		`, scheduleID, tenantID).Scan(&assignedStaffUserID, &scheduleStatus, &pendingStaffID)
544		if err != nil {
545			return c.JSON(http.StatusNotFound, map[string]string{"error": "Schedule not found"})
546		}
547	
548		isReassignment := scheduleStatus == "pending_reassignment" && pendingStaffID != nil
549	
550		if isReassignment {
551			// For reassignment: the new (pending) staff member or Admin must confirm
552			var pendingStaffUserID uuid.UUID
553			_ = h.DB.QueryRow("SELECT user_id FROM staff_roster WHERE id = $1", *pendingStaffID).Scan(&pendingStaffUserID)
554			if currentUser.ID != pendingStaffUserID && currentUser.RoleName != "Administrator" {
555				return c.JSON(http.StatusForbidden, map[string]string{
556					"error": "Only the reassigned staff member or an Administrator can confirm this reassignment",
557				})
558			}
559		} else {
560			// For initial assignment: the assigned staff member or Admin must confirm
561			if currentUser.ID != assignedStaffUserID && currentUser.RoleName != "Administrator" {
562				return c.JSON(http.StatusForbidden, map[string]string{
563					"error": "Only the assigned staff member or an Administrator can confirm this assignment",
564				})
565			}
566		}
567	
568		now := time.Now()
569		var result sql.Result
570		if isReassignment {
571			// Confirm reassignment: swap staff_id to pending_staff_id, clear pending
572			result, err = h.DB.Exec(`
573				UPDATE schedules
574				SET staff_id = pending_staff_id, pending_staff_id = NULL,
575				    status = 'confirmed', confirmed_at = $1, updated_at = $2,
576				    requires_confirmation = FALSE
577				WHERE id = $3 AND tenant_id = $4 AND status = 'pending_reassignment' AND pending_staff_id IS NOT NULL
578			`, now, now, scheduleID, tenantID)
579		} else {
580			result, err = h.DB.Exec(`
581				UPDATE schedules
582				SET status = 'confirmed', confirmed_at = $1, updated_at = $2
583				WHERE id = $3 AND tenant_id = $4 AND requires_confirmation = TRUE AND status = 'pending'
584			`, now, now, scheduleID, tenantID)
585		}
586		if err != nil {
587			return c.JSON(http.StatusInternalServerError, map[string]string{
588				"error": "Failed to confirm assignment",
589			})
590		}
591	
592		rowsAffected, _ := result.RowsAffected()
593		if rowsAffected == 0 {
594			return c.JSON(http.StatusNotFound, map[string]string{
595				"error": "Schedule not found or does not require confirmation",
596			})
597		}
598	
599		action := "confirm_assignment"
600		if isReassignment {
601			action = "confirm_reassignment"
602		}
603		if err := writeCriticalAuditLog(h.AL, h.DB, &tenantID, &currentUser.ID, action, "schedule", &scheduleID, nil, c.RealIP()); err != nil {
604			return c.JSON(http.StatusInternalServerError, map[string]string{
605				"error": "Audit system unavailable, action denied",
606			})
607		}
608	
609		return h.getScheduleByID(c, scheduleID, tenantID, http.StatusOK)
610	}
