68	-- ----------------------------------------------------------------------------
69	-- 7. Audit ledger immutability: DB-level triggers to prevent UPDATE/DELETE
70	-- ----------------------------------------------------------------------------
71	CREATE OR REPLACE FUNCTION prevent_audit_ledger_modification()
72	RETURNS TRIGGER AS $$
73	BEGIN
74	    RAISE EXCEPTION 'audit_ledger is append-only: % operations are not allowed', TG_OP;
75	    RETURN NULL;
76	END;
