112	-- 7b. Protect critical audit_logs entries from mutation
113	-- ----------------------------------------------------------------------------
114	CREATE OR REPLACE FUNCTION prevent_critical_audit_log_modification()
115	RETURNS trigger AS $$
116	DECLARE
117	    critical_actions TEXT[] := ARRAY[
118	        'login', 'logout', 'login_failed',
119	        'create_user', 'deactivate_user', 'update_user_role',
120	        'review_decision', 'promote_content', 'rollback_content',
121	        'create_schedule', 'cancel_schedule', 'confirm_assignment', 'reassign_schedule',
122	        'store_sensitive_data', 'reveal_sensitive_data', 'rotate_encryption_key',
123	        'resolve_exception', 'assign_exception'
124	    ];
125	BEGIN
126	    IF OLD.action = ANY(critical_actions) THEN
127	        RAISE EXCEPTION 'Cannot modify or delete critical audit log entries (action: %)', OLD.action;
128	        RETURN NULL;
129	    END IF;
130	    IF TG_OP = 'DELETE' THEN
131	        RETURN OLD;
132	    END IF;
133	    RETURN NEW;
134	END;
135	$$ LANGUAGE plpgsql;
