import (
	"testing"
)

// levenshteinDistance mirrors the production implementation in
// backend/internal/services/reconciliation.go.
func levenshteinDistance(a, b string) int {
	la, lb := len(a), len(b)
	if la == 0 {
		return lb
	}
	if lb == 0 {
		return la
	}

	prev := make([]int, lb+1)
	curr := make([]int, lb+1)
	for j := 0; j <= lb; j++ {
		prev[j] = j
	}

	for i := 1; i <= la; i++ {
		curr[0] = i
		for j := 1; j <= lb; j++ {
			cost := 1
			if a[i-1] == b[j-1] {
				cost = 0
			}
			curr[j] = min(curr[j-1]+1, min(prev[j]+1, prev[j-1]+cost))
		}
		prev, curr = curr, prev
	}
	return prev[lb]
}

func levenshteinSimilarity(a, b string) float64 {
	maxLen := len(a)
	if len(b) > maxLen {
		maxLen = len(b)
	}
	if maxLen == 0 {
		return 1.0
	}
	dist := levenshteinDistance(a, b)
	return 1.0 - float64(dist)/float64(maxLen)
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func TestLevenshteinDistance(t *testing.T) {
	tests := []struct {
		name     string
		a, b     string
		expected int
	}{
		{"identical strings", "hello", "hello", 0},
		{"empty vs empty", "", "", 0},
		{"empty vs non-empty", "", "abc", 3},
		{"non-empty vs empty", "abc", "", 3},
		{"single char difference", "cat", "bat", 1},
		{"insertion", "cat", "cats", 1},
		{"deletion", "cats", "cat", 1},
		{"transposition", "ab", "ba", 2},
		{"completely different", "abc", "xyz", 3},
		{"different lengths", "short", "longer string", 10},
		{"case sensitive", "Hello", "hello", 1},
		{"single char strings", "a", "b", 1},
		{"repeated chars", "aaa", "aaaa", 1},
