		tampered := make([]ledgerEntry, len(chain))
		copy(tampered, chain)
		tampered[0].createdAt = tampered[0].createdAt.Add(time.Second)
		valid, _ := verifyChain(tampered)
		if valid {
			t.Error("timestamp-tampered chain should fail verification")
		}
	})

