	ts := time.Now()
	h := computeEntryHash("prev", "t1", "u1", "login", "session", "s1", "{}", ts)
	// SHA-256 produces 64 hex characters
	if len(h) != 64 {
		t.Errorf("hash length = %d, want 64", len(h))
	}
}
